actions.script:
// SECURITY (admin gate): minting a public API key for ANY tenant is super-admin-only.
// Without this any authenticated user could self-serve a cross-tenant public key. Fail-closed.
if (!darpan.facade.common.TenantAccessSupport.isSuperAdmin(ec)) {
    ec.message.addError("Minting a public GraphQL API key requires super-admin.")
    return
}
// 256 bits of entropy from SecureRandom, URL-safe base64 (no padding), prefixed "dgql_".
String rawKey = org.moqui.gql.auth.ApiKeyHasher.generateRawKey()
// Store ONLY the hash. NEVER persist or log rawKey.
String keyHash = org.moqui.gql.auth.ApiKeyHasher.sha256Hex(rawKey)
String newId = ec.entity.sequencedIdPrimary("moqui.gql.GqlApiKey", null, null)
ec.entity.makeValue("moqui.gql.GqlApiKey").setAll([
        apiKeyId: newId, keyHash: keyHash, companyUserGroupId: companyUserGroupId,
        profileId: profileId, clientName: clientName, enabled: "Y",
        expireDate: expireDate, createdDate: ec.user.nowTimestamp]).create()
apiKeyId = newId
apiKey = rawKey
// Log identity only — never the raw key or its hash.
ec.logger.info("gql: minted API key apiKeyId=${newId} client='${clientName}' tenant=${companyUserGroupId}")

valid = false
// Fail-closed: a missing/blank/empty key never resolves as valid.
if (apiKey == null || apiKey.toString().trim().isEmpty()) {
    ec.message.addError("invalid API key")
    return
}
String keyHash = org.moqui.gql.auth.ApiKeyHasher.sha256Hex(apiKey.toString())
// System lookup by HASH (disableAuthz: this runs under the anonymous public realm). Exact
// equality on the unique keyHash index — never a substring/like match.
def row = ec.entity.find("moqui.gql.GqlApiKey").condition("keyHash", keyHash)
        .disableAuthz().useCache(false).one()
java.sql.Timestamp now = ec.user.nowTimestamp
boolean ok = row != null &&
        "Y".equals(row.enabled) &&
        (row.expireDate == null || ((java.sql.Timestamp) row.expireDate).after(now))
if (!ok) {
    // Do NOT leak which check failed beyond the generic message.
    ec.message.addError("invalid API key")
    return
}
valid = true
companyUserGroupId = row.companyUserGroupId
profileId = row.profileId
apiKeyId = row.apiKeyId
clientName = row.clientName
// Best-effort lastUsedDate update — must never fail/abort the resolution. Own transaction
// so it can't be poisoned by the read-only query transaction.
try {
    ec.transaction.runRequireNew(10, "gql api-key lastUsed update error", {
        ec.entity.find("moqui.gql.GqlApiKey").condition("apiKeyId", row.apiKeyId)
                .disableAuthz().one()?.set("lastUsedDate", now)?.update()
    })
} catch (Throwable t) {
    ec.logger.warn("gql: api-key lastUsedDate update failed for apiKeyId=${row.apiKeyId}: " + t.message)
}
